{
  "sentences": [
    {
      "text": "你是不是說錯的意思？",
      "pinyin": "Nǐ shì bù shì shuō cuò de yìsi?",
      "pinyin_numeric": "ni3 shi4 bu4 shi4 shuo1 cuo4 de0 yi4 si0",
      "translation_en": "Is it that you said it wrong?",
      "translation_ko": "당신이 잘못 말한 건가요?"
    },
    {
      "text": "他是不是誤會我的意思？",
      "pinyin": "Tā shì bù shì wùhuì wǒ de yìsi?",
      "pinyin_numeric": "ta1 shi4 bu4 shi4 wu4 hui4 wo3 de0 yi4 si0",
      "translation_en": "Is it that he misunderstood me?",
      "translation_ko": "그가 제 뜻을 오해한 건가요?"
    },
    {
      "text": "你是不是以為我生氣的？",
      "pinyin": "Nǐ shì bù shì yǐwéi wǒ shēngqì de?",
      "pinyin_numeric": "ni3 shi4 bu4 shi4 yi3 wei2 wo3 sheng1 qi4 de0",
      "translation_en": "Is it that you thought I was angry?",
      "translation_ko": "당신은 제가 화난 줄 알았나요?"
    },
    {
      "text": "這個句子是不是有錯誤的意思？",
      "pinyin": "Zhège jùzi shì bù shì yǒu cuòwù de yìsi?",
      "pinyin_numeric": "zhe4 ge0 ju4 zi0 shi4 bu4 shi4 you3 cuo4 wu4 de0 yi4 si0",
      "translation_en": "Is it that this sentence has a wrong meaning?",
      "translation_ko": "이 문장이 잘못된 뜻을 가지고 있나요?"
    },
    {
      "text": "你的答案是不是跟我的不一樣的意思？",
      "pinyin": "Nǐ de dá'àn shì bù shì gēn wǒ de bù yīyàng de yìsi?",
      "pinyin_numeric": "ni3 de0 da2 an4 shi4 bu4 shi4 gen1 wo3 de0 bu4 yi1 yang4 de0 yi4 si0",
      "translation_en": "Is it that your answer is different from mine?",
      "translation_ko": "당신의 답이 제 것과 다른 뜻인가요?"
    },
    {
      "text": "你是不是想說「對不起」的意思？",
      "pinyin": "Nǐ shì bù shì xiǎng shuō duìbuqǐ de yìsi?",
      "pinyin_numeric": "ni3 shi4 bu4 shi4 xiang3 shuo1 dui4 bu4 qi3 de0 yi4 si0",
      "translation_en": "Is it that you want to say 'sorry'?",
      "translation_ko": "당신이 '죄송합니다'라고 말하고 싶은 뜻인가요?"
    },
    {
      "text": "他是不是聽懂我的意思？",
      "pinyin": "Tā shì bù shì tīng dǒng wǒ de yìsi?",
      "pinyin_numeric": "ta1 shi4 bu4 shi4 ting1 dong3 wo3 de0 yi4 si0",
      "translation_en": "Is it that he understood me?",
      "translation_ko": "그가 제 뜻을 이해한 건가요?"
    },
    {
      "text": "你是不是需要我解釋清楚的意思？",
      "pinyin": "Nǐ shì bù shì xūyào wǒ jiěshì qīngchu de yìsi?",
      "pinyin_numeric": "ni3 shi4 bu4 shi4 xu1 yao4 wo3 jie3 shi4 qing1 chu0 de0 yi4 si0",
      "translation_en": "Is it that you need me to explain clearly?",
      "translation_ko": "당신이 제가 명확히 설명해 주길 바라는 뜻인가요?"
    },
    {
      "text": "這個問題是不是有兩個意思？",
      "pinyin": "Zhège wèntí shì bù shì yǒu liǎng ge yìsi?",
      "pinyin_numeric": "zhe4 ge0 wen4 ti2 shi4 bu4 shi4 you3 liang3 ge0 yi4 si0",
      "translation_en": "Is it that this question has two meanings?",
      "translation_ko": "이 질문이 두 가지 뜻을 가지고 있나요?"
    },
    {
      "text": "你是不是覺得我說錯的意思？",
      "pinyin": "Nǐ shì bù shì juéde wǒ shuō cuò de yìsi?",
      "pinyin_numeric": "ni3 shi4 bu4 shi4 jue2 de0 wo3 shuo1 cuo4 de0 yi4 si0",
      "translation_en": "Is it that you think I said it wrong?",
      "translation_ko": "당신이 제가 잘못 말했다고 생각하는 뜻인가요?"
    }
  ]
}
